    IS_LAST_DIM   = 29
    POS_LIN_DIM   = 30
    POS_QUAD_DIM  = 31
    POS_CONST_DIM = 32
    PREV_BASE     = 33   # ..60  (28 prev-char dims)
    PPREV_BASE    = 61   # ..88  (28 prev-prev-char dims)
    BIG_BASE      = 89                # ..(88+Kb)  bigram detectors / counts (overlap)
    Kb_const      = 450
    Kt_const      = 1500
    TRI_BASE      = BIG_BASE + Kb_const   # ..(BIG_BASE+Kb+Kt-1)  trigram detectors / counts
